export function IcoWaypointOpt() {
  const { palette } = useIlloStyle();
  return (
    <svg viewBox="0 0 200 130" preserveAspectRatio="xMidYMid slice" style={{ width: '100%', height: '100%' }}>
      <rect width="200" height="130" fill={palette.dark} />
      {/* Route line */}
      <path d="M 22,65 L 55,65 L 78,40 L 100,65 L 122,90 L 145,65 L 178,65" fill="none" stroke={palette.mid} strokeWidth="3.5" strokeLinecap="round" strokeLinejoin="round" />
      {/* Start/end dots */}
      <circle cx="22" cy="65" r="8" fill={palette.accent} />
      <circle cx="178" cy="65" r="8" fill={palette.accent} />
      {/* Waypoint diamonds */}
      {[78, 100, 122].map((x, i) => {
        const y = i === 0 ? 40 : i === 1 ? 65 : 90;
        return (
          <polygon key={x} points={`${x},${y - 9} ${x + 9},${y} ${x},${y + 9} ${x - 9},${y}`} fill={palette.mid} stroke={palette.accent} strokeWidth="2" />
        );
      })}
    </svg>
  );
}
